// ═══════════════════════════════════════════════════════════════════════════
// NODE 2: PREPARE PROMPT - DYNAMIC ROUTING FOR MOLTCORP & NUMERAI
// ═══════════════════════════════════════════════════════════════════════════

const input = $input.first().json.body || $input.first().json;
const platform = input.target_platform || 'Moltcorp';
const taskType = input.task_type || 'PR_Audit';
const rawData = input.raw_data || {};
const context = input.context || '';
const metadata = input.metadata || {};

const PROMPTS = {
  Numerai: {
    Model_Optimization: {
      deepseek_r1: {
        role: 'Quant Judge',
        system: `You are DeepSeek-R1, the QUANT JUDGE of the Tri-Model Council.
Review XGBoost/LightGBM parameter sets for Numerai tournament.
Look for overfitting risks against v5.0/live.parquet dataset.
OUTPUT:
1. Risk Assessment (0-10)
2. Parameter Analysis
3. Mathematical Critique
4. Recommended Adjustments
5. Expected MMC Impact`,
        temperature: 0.2
      },
      qwen3: {
        role: 'Feature Architect',
        system: `You are Qwen3.5, the FEATURE ARCHITECT.
Analyze parameters from architectural perspective.
Consider feature interaction depth, computational efficiency.
OUTPUT:
1. Architecture Assessment
2. Feature Utilization
3. Generalization Score
4. Optimization Suggestions`,
        temperature: 0.4
      },
      kimi_k2: {
        role: 'Meta-Strategist',
        system: `You are Kimi K2, the META-STRATEGIST.
Synthesize perspectives for strategic guidance.
Consider correlation targets, stake sizing.
OUTPUT:
1. Strategic Summary
2. Risk-Adjusted Recommendation
3. Stake Suggestion
4. Expected Performance`,
        temperature: 0.4
      }
    }
  },
  Moltcorp: {
    PR_Audit: {
      deepseek_r1: {
        role: 'Security Auditor',
        system: `RUTHLESS security analysis for MOLTCORP/SuperZ platform.
Check SQL injection, XSS, auth bypasses, payment gateway issues.
OUTPUT:
1. Security Score (0-100)
2. Critical Issues
3. Warnings
4. Suggestions
5. PASS/FAIL`,
        temperature: 0.1
      },
      qwen3: {
        role: 'Code Architect',
        system: `Analyze code structure, design patterns, performance for Apex fintech platform.
OUTPUT:
1. Architecture Score
2. Code Quality Analysis
3. Performance Impact
4. Refactoring Recommendations
5. PASS/CONDITIONAL/FAIL`,
        temperature: 0.3
      },
      kimi_k2: {
        role: 'UX Guardian',
        system: `Protect African Futurism UI vision for SuperZ/Moltcorp.
OUTPUT:
1. UX Impact Score
2. User Flow Analysis
3. Accessibility Check
4. Design Consistency
5. APPROVE/FLAG/REJECT`,
        temperature: 0.4
      }
    }
  }
};

const platformPrompts = PROMPTS[platform];
const taskPrompts = platformPrompts?.[taskType] || platformPrompts?.Model_Optimization || PROMPTS.Moltcorp.PR_Audit;

return [{
  json: {
    platform,
    taskType,
    timestamp: new Date().toISOString(),
    botName: 'VAAL_MONEY_BOT',
    rawData,
    context,
    modelPrompts: {
      deepseek_r1: {
        model: 'deepseek-v3.2',
        role: taskPrompts.deepseek_r1.role,
        system_prompt: taskPrompts.deepseek_r1.system,
        user_prompt: `TASK: ${taskType}\nPLATFORM: ${platform}\nDATA: ${JSON.stringify(rawData, null, 2)}\nCONTEXT: ${context}`,
        temperature: taskPrompts.deepseek_r1.temperature
      },
      qwen3: {
        model: 'qwen3.5:397b',
        role: taskPrompts.qwen3.role,
        system_prompt: taskPrompts.qwen3.system,
        user_prompt: `TASK: ${taskType}\nPLATFORM: ${platform}\nDATA: ${JSON.stringify(rawData, null, 2)}\nCONTEXT: ${context}`,
        temperature: taskPrompts.qwen3.temperature
      },
      kimi_k2: {
        model: 'kimi-k2-thinking',
        role: taskPrompts.kimi_k2.role,
        system_prompt: taskPrompts.kimi_k2.system,
        user_prompt: `TASK: ${taskType}\nPLATFORM: ${platform}\nDATA: ${JSON.stringify(rawData, null, 2)}\nCONTEXT: ${context}`,
        temperature: taskPrompts.kimi_k2.temperature
      }
    },
    originalPayload: { raw_data: rawData, context, metadata }
  }
}];

// ═══════════════════════════════════════════════════════════════════════════
// NODE 5: STRIP THINKING TAGS - CLEAN OUTPUT FOR ALL 3 MODELS
// ═══════════════════════════════════════════════════════════════════════════

const items = $input.all();
const models = [
  { id: 'deepseek-r1', label: 'DeepSeek-R1 (Reasoning)', inputPort: 0 },
  { id: 'qwen3', label: 'Qwen3.5 (Analysis)', inputPort: 1 },
  { id: 'kimi-k2', label: 'Kimi K2 (Thinking)', inputPort: 2 },
];

return items.map((item, i) => {
  const raw = item.json.response || item.json.message?.content || '[no response]';
  // Strip thinking tags from Kimi output
  const cleaned = raw.replace(/<think[\s\S]*?<\/think>/gi, '').replace(/<think[\s\S]*$/gi, '').trim();
  const timedOut = raw === '[no response]' || cleaned.length < 10;

  return { json: {
    model_id: models[i]?.id || `model_${i}`,
    model_label: models[i]?.label || `Model ${i}`,
    raw_response: raw,
    response: cleaned,
    word_count: cleaned.split(/\s+/).length,
    timed_out: timedOut,
    eval_count: item.json.eval_count || 0,
    duration_ms: Math.round((item.json.total_duration || 0) / 1e6),
    platform: $('2. Prepare Prompt - Moltcorp/SuperZ').item.json.platform,
    taskType: $('2. Prepare Prompt - Moltcorp/SuperZ').item.json.taskType
  }};
});

// ═══════════════════════════════════════════════════════════════════════════
// NODE 7: ENTERPRISE SCORE RESPONSES - ALGORITHMIC CONSENSUS
// ═══════════════════════════════════════════════════════════════════════════

const items = $input.all();
const platform = items[0]?.json.platform || 'Moltcorp';

// Score each response
const scored = items.map(item => {
  const { model_id, response, word_count, timed_out } = item.json;
  if (timed_out) return { ...item.json, score: 0, scoreBreakdown: {}, hard_fail: false };

  const text = response.toLowerCase();
  let score = 0;
  let breakdown = {};
  let hardFail = false;

  // 1. Structure Score (Max 20)
  const hasSections = (response.match(/^#|^\d+\./gm) || []).length;
  breakdown.structure = Math.min(20, hasSections * 5);
  score += breakdown.structure;

  // 2. Domain Keywords (Max 40)
  let keywords = [];
  if (platform === 'Numerai') {
    keywords = ['MMC', 'correlation', 'overfitting', 'Kelly', 'XGBoost', 'feature', 'risk', 'stake', 'yield'];
  } else {
    keywords = ['vulnerability', 'O(n)', 'latency', 'UX', 'injection', 'refactor', 'efficiency', 'security', 'auth'];
  }
  const matchedWords = keywords.filter(k => text.includes(k.toLowerCase())).length;
  breakdown.domain_knowledge = Math.min(40, matchedWords * 5);
  score += breakdown.domain_knowledge;

  // 3. Signal Strength (Max 40)
  const signalWords = ['recommend', 'critical', 'fail', 'pass', 'approve', 'adjust', 'reject'];
  const signalMatches = signalWords.filter(w => text.includes(w)).length;
  breakdown.signal = Math.min(40, signalMatches * 8);
  score += breakdown.signal;

  // 4. Model-Specific Scoring
  if (model_id === 'deepseek-r1') {
    // Security/Logic weight: higher for pass/fail
    if (text.includes('fail') || text.includes('critical')) {
      hardFail = true;
      breakdown.security_gate = 30;
    } else if (text.includes('pass')) {
      breakdown.security_gate = 20;
    }
    score += breakdown.security_gate || 0;
  } else if (model_id === 'qwen3') {
    // Code quality weight
    const scoreMatch = text.match(/score[:\s]+(\d+)/);
    if (scoreMatch) {
      breakdown.code_quality = parseInt(scoreMatch[1]) / 2.5;
      score += breakdown.code_quality;
    }
  } else if (model_id === 'kimi-k2') {
    // UX impact weight
    const impactMap = { low: 10, medium: 20, high: 30 };
    const impactMatch = text.match(/ux.?impact[:\s]*(low|medium|high)/);
    if (impactMatch) {
      breakdown.ux_impact = impactMap[impactMatch[1]] || 15;
      score += breakdown.ux_impact;
    }
  }

  // 5. Hallucination Penalty (Negative)
  const waffleWords = ['as an ai', 'important to note', 'in conclusion', 'delve', 'i cannot'];
  const waffleCount = waffleWords.filter(w => text.includes(w)).length;
  breakdown.penalty = -(waffleCount * 8);
  score += breakdown.penalty;

  return { ...item.json, score: Math.max(0, Math.round(score)), scoreBreakdown: breakdown, hard_fail: hardFail };
});

// Sort by score with tie-breaker favoring DeepSeek for logic
const sorted = [...scored].sort((a, b) => {
  if (b.score === a.score) {
    if (a.model_id === 'deepseek-r1') return -1;
    if (b.model_id === 'deepseek-r1') return 1;
  }
  return b.score - a.score;
});

let winner = sorted[0];
const deepseekResult = scored.find(s => s.model_id === 'deepseek-r1');
const hardFail = deepseekResult?.hard_fail === true;

// FIX: Hard-fail forces DeepSeek as authoritative winner
if (hardFail && deepseekResult) {
  winner = deepseekResult;
  // consensusAchieved will be false because hardFail is true (computed below)
}

const allScores = {};
scored.forEach(r => { allScores[r.model_id] = r.score; });

const avgScore = scored.reduce((sum, r) => sum + r.score, 0) / scored.length;
const consensusAchieved = winner.score >= 60 && !hardFail;

return [{ json: {
  best_model: winner.model_id,
  best_label: winner.model_label,
  best_response: winner.response,
  best_score: winner.score,
  hard_fail: hardFail,
  consensus_achieved: consensusAchieved,
  all_scores: allScores,
  all_responses: scored.map(s => ({
    model: s.model_label,
    score: s.score,
    words: s.word_count,
    duration_ms: s.duration_ms,
    timed_out: s.timed_out
  })),
  platform,
  taskType: items[0]?.json.taskType || 'unknown',
  timestamp: new Date().toISOString()
}}];
